mapper.select:
SELECT * FROM user_memory
WHERE user_id = #{userId}
ORDER BY importance DESC, updated_at DESC

SELECT * FROM user_memory
WHERE user_id = #{userId} AND memory_type = #{memoryType}
ORDER BY importance DESC, updated_at DESC

SELECT * FROM user_preference
WHERE user_id = #{userId}
ORDER BY confidence DESC

SELECT * FROM user_preference
WHERE user_id = #{userId} AND preference_key = #{preferenceKey}
LIMIT 1

mapper.update:
UPDATE user_preference
SET preference_value = #{preferenceValue},
    confidence = #{confidence},
    sample_count = #{sampleCount},
    updated_at = #{updatedAt}
WHERE id = #{id}

mapper.select:
SELECT * FROM user_habit
WHERE user_id = #{userId}
ORDER BY frequency DESC

SELECT * FROM user_habit
WHERE user_id = #{userId} AND habit_type = #{habitType} AND habit_key = #{habitKey}
LIMIT 1

SELECT * FROM user_habit
WHERE user_id = #{userId}
ORDER BY frequency DESC
LIMIT #{limit}
